const t={hostControl:{intro:{t:0,b:{t:2,i:[{t:3}],s:"管理打印机的 Linux 主机——查看其健康状况和操作系统状态。服务、磁盘清理和系统设置将在后续阶段加入。"}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"这是什么？"}},body:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind 运行在打印机的小型 Linux 计算机（主机）上。此面板读取该计算机的实时健康状况和操作系统状态，让你无需打开终端即可发现问题——CPU 过热、磁盘已满、时钟未同步等。"}},step1:{t:0,b:{t:2,i:[{t:3}],s:"一眼浏览 CPU 温度、内存、磁盘和网络的卡片。"}},step2:{t:0,b:{t:2,i:[{t:3}],s:"查看占用最高的进程表格，了解当前是什么在使用 CPU。"}},step3:{t:0,b:{t:2,i:[{t:3}],s:"保持自动刷新开启以获得实时视图，或将其关闭并手动刷新。"}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"此处使用的术语"}}},monitor:{title:{t:0,b:{t:2,i:[{t:3}],s:"读懂监视器"}},body:{t:0,b:{t:2,i:[{t:3}],s:"此处全部为只读。进度条超过 75% 变为琥珀色，超过 90% 变为红色。CPU 温度在 70 °C 变为琥珀色，在 80 °C 变为红色。降频警告仅在会报告该信息的主板上显示（主要是 Raspberry Pi）。"}}}},glossary:{host:{term:{t:0,b:{t:2,i:[{t:3}],s:"主机"}},def:{t:0,b:{t:2,i:[{t:3}],s:"运行 Klipper、Moonraker 和 FilaMind 的小型 Linux 计算机（例如 Raspberry Pi 或 BTT CB1）——与打印机的微控制器相互独立。"}}},load:{term:{t:0,b:{t:2,i:[{t:3}],s:"平均负载"}},def:{t:0,b:{t:2,i:[{t:3}],s:"在 1 / 5 / 15 分钟内等待运行的进程数量的平均值。大致来说：接近核心数的值表示 CPU 繁忙；远高于核心数表示已过载。"}}},swap:{term:{t:0,b:{t:2,i:[{t:3}],s:"交换分区（Swap）"}},def:{t:0,b:{t:2,i:[{t:3}],s:"内存占满时用作溢出的磁盘空间。频繁使用交换会拖慢主机——这是内存不足的信号。"}}},throttle:{term:{t:0,b:{t:2,i:[{t:3}],s:"降频限速"}},def:{t:0,b:{t:2,i:[{t:3}],s:"主板为保护自身而降低速度——通常是因为供电不足（欠压）或过热。主要在 Raspberry Pi 上报告。"}}},ntp:{term:{t:0,b:{t:2,i:[{t:3}],s:"NTP / 时钟同步"}},def:{t:0,b:{t:2,i:[{t:3}],s:"网络时间协议使主机时钟保持准确。未同步的时钟可能导致延时摄影、日志和 TLS 证书出错。"}}},locale:{term:{t:0,b:{t:2,i:[{t:3}],s:"区域设置（Locale）"}},def:{t:0,b:{t:2,i:[{t:3}],s:"主机的语言和键盘布局设置，操作系统用它来处理文本、日期和控制台键盘映射。"}}}}},monitor:{refresh:{t:0,b:{t:2,i:[{t:3}],s:"刷新"}},autoRefresh:{t:0,b:{t:2,i:[{t:3}],s:"自动刷新"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"正在读取主机状态…"}},host:{t:0,b:{t:2,i:[{t:3}],s:"主机"}},hostname:{t:0,b:{t:2,i:[{t:3}],s:"主机名"}},distro:{t:0,b:{t:2,i:[{t:3}],s:"操作系统"}},kernel:{t:0,b:{t:2,i:[{t:3}],s:"内核"}},uptime:{t:0,b:{t:2,i:[{t:3}],s:"运行时间"}},cpu:{t:0,b:{t:2,i:[{t:3}],s:"CPU"}},temp:{t:0,b:{t:2,i:[{t:3}],s:"温度"}},load:{t:0,b:{t:2,i:[{t:3}],s:"负载 (1·5·15 分钟)"}},cores:{t:0,b:{t:2,i:[{t:3}],s:"核心数"}},throttled:{t:0,b:{t:2,i:[{t:3}],s:"已降频"}},memory:{t:0,b:{t:2,i:[{t:3}],s:"内存"}},ram:{t:0,b:{t:2,i:[{t:3}],s:"RAM"}},swap:{t:0,b:{t:2,i:[{t:3}],s:"交换"}},disk:{t:0,b:{t:2,i:[{t:3}],s:"磁盘"}},network:{t:0,b:{t:2,i:[{t:3}],s:"网络"}},iface:{t:0,b:{t:2,i:[{t:3}],s:"接口"}},ip:{t:0,b:{t:2,i:[{t:3}],s:"IP 地址"}},ssid:{t:0,b:{t:2,i:[{t:3}],s:"Wi-Fi"}},signal:{t:0,b:{t:2,i:[{t:3}],s:"信号"}},timeLocale:{t:0,b:{t:2,i:[{t:3}],s:"时间与区域"}},timezone:{t:0,b:{t:2,i:[{t:3}],s:"时区"}},ntp:{t:0,b:{t:2,i:[{t:3}],s:"时钟同步"}},synced:{t:0,b:{t:2,i:[{t:3}],s:"已同步"}},syncing:{t:0,b:{t:2,i:[{t:3}],s:"同步中…"}},ntpOff:{t:0,b:{t:2,i:[{t:3}],s:"关闭"}},language:{t:0,b:{t:2,i:[{t:3}],s:"语言"}},keymap:{t:0,b:{t:2,i:[{t:3}],s:"键盘布局"}},topProcesses:{t:0,b:{t:2,i:[{t:3}],s:"占用最高的进程"}},command:{t:0,b:{t:2,i:[{t:3}],s:"命令"}},cpuPct:{t:0,b:{t:2,i:[{t:3}],s:"CPU%"}},memPct:{t:0,b:{t:2,i:[{t:3}],s:"内存%"}},pid:{t:0,b:{t:2,i:[{t:3}],s:"PID"}}}}};export{t as default};
